  <div class="status-bar-data-container">$1</div>
  <div class="status-bar-container">
    <div class="status-bar-header"></div>
    <div class="left-column"></div>
    <div class="right-column"></div>
  </div>
  <script>
    document.addEventListener('DOMContentLoaded', () => {
      const dataContainer = document.querySelector('.status-bar-data-container');
      if (!dataContainer) return;

      const headerArea = document.querySelector('.status-bar-header');
      const leftColumn = document.querySelector('.left-column');
      const rightColumn = document.querySelector('.right-column');
      if (!headerArea || !leftColumn || !rightColumn) return;

      function parseData(text) {
          const data = {};
          const blockRegex = /\[([^\]]+)\]([\s\S]*?)\[\/\1\]/g;
          let match;
          data.blocks = [];
          while ((match = blockRegex.exec(text)) !== null) {
              const blockName = match[1].trim();
              if (blockName.toLowerCase() === 'config' || blockName.toLowerCase() === '本期焦点') continue;
              const blockContent = match[2].trim();
              const items = {};
              const lines = blockContent.split('\n');
              lines.forEach(line => {
                  const parts = line.match(/^([^:]+):\s*(.*)/);
                  if (parts) {
                      items[parts[1].trim()] = parts[2].trim();
                  }
              });
              data.blocks.push({ name: blockName, items: items });
          }
          return data;
      }

      function renderData(data) {
        leftColumn.innerHTML = '';
        rightColumn.innerHTML = '';
        headerArea.innerHTML = '';

        const coverStory = data.blocks.find(b => b.name === '封面故事');
        if (coverStory) {
          headerArea.innerHTML = `
            <div class="main-title">${coverStory.items['主打标题'] || '本期焦点'}</div>
            <p class="quote">${coverStory.items['引言'] || ''}</p>
          `;
        }

        const blocksMap = new Map(data.blocks.map(b => [b.name, b]));
        const leftColumnBlocks = ['生命体征', '核心档案', '专业评估'];
        const rightColumnBlocks = ['价值分析', '圈内观察', '时局变数'];

        leftColumnBlocks.forEach(name => {
            if (blocksMap.has(name)) leftColumn.appendChild(createBlock(blocksMap.get(name)));
        });

        rightColumnBlocks.forEach(name => {
             if (blocksMap.has(name)) rightColumn.appendChild(createBlock(blocksMap.get(name)));
        });
      }

      function createBlock(block) {
          const blockDiv = document.createElement('div');
          blockDiv.className = 'data-block';

          let itemsHTML = `<div class="data-block-title">${block.name}</div>`;

          for (const key in block.items) {
              // **核心修改逻辑**
              // 定义一个数组，包含所有我们认为可能需要长文本空间的字段的Key
              const longTextKeys = ['时代风向', '引言', '主打标题', '履历亮点', '业界评价', '当前机遇', '潜在风险'];

              // 判断当前的Key是否在数组中
              const itemClass = longTextKeys.includes(key)
                                ? 'data-item long-text-item' // 如果是，应用特殊class
                                : 'data-item'; // 如果不是，使用默认class

              itemsHTML += `
                <div class="${itemClass}">
                  <span class="data-key">${key}</span>
                  <span class="data-value">${block.items[key]}</span>
                </div>`;
          }
          blockDiv.innerHTML = itemsHTML;
          return blockDiv;
      }

      const rawData = dataContainer.textContent.trim();
      if (rawData) {
        const parsedData = parseData(rawData);
        renderData(parsedData);
      }
    });
  </script>
